module.exports.run = async function({ api, event, Users }) {
  var { threadID, messageID, senderID } = event;
  if (!event.body) return;
  var name = await Users.getNameUser(senderID);
  var userData = Users.getData(senderID) || {};
  var savedLang = userData.lang || "roman";

  var input = event.body.toLowerCase().trim();
  var lang = savedLang;
  var isLangChange = false;
  var cleanInput = " " + input + " ";
  var isBotTriggered = cleanInput.includes(" bot ") || input.startsWith("bot");

  if (!isBotTriggered) {
    return;
  }


  if (input === "bot ur") { lang = "ur"; isLangChange = true; }
  else if (input === "bot bd") { lang = "bd"; isLangChange = true; }
  else if (input === "bot hi") { lang = "hi"; isLangChange = true; }
  else if (input === "bot np") { lang = "np"; isLangChange = true; }
  else if (input === "bot ar") { lang = "ar"; isLangChange = true; }
  else if (input === "bot en") { lang = "en"; isLangChange = true; }
  else if (input === "bot roman") { lang = "roman"; isLangChange = true; }
  else if (input === "bot reset" || input === "bot r") {
    userData.lang = "roman";
    Users.setData(senderID, userData);
    return api.sendMessage("✅ Language reset to Roman Urdu!", threadID, messageID);
  }

  if (isLangChange) {
    userData.lang = lang;
    Users.setData(senderID, userData);
    const langNames = { en: "English", ur: "اردو", bd: "বাংলা", hi: "हिन्दी", np: "नेपाली", ar: "العربية", roman: "Roman Urdu" };
    return api.sendMessage(`✅ Language set to ${langNames[lang]}!\nAb bot ${langNames[lang]} mein reply karyga.`, threadID, messageID);
  }

  if (input.startsWith("bot")) {
    userData.lang = lang;
    Users.setData(senderID, userData);

    var tl = allTexts[lang];
    var rand = tl[Math.floor(Math.random() * tl.length)];
    const langNames = { en: "English", ur: "Urdu", bd: "Bengali", hi: "Hindi", np: "Nepali", ar: "Arabic", roman: "Roman Urdu" };
    const formattedMessage = {
      body: `🧡★━━━━━✩━━━━━★💥\n𝐍𝐚𝐦𝐞 🐣:-\n@${name} \n≪━─━─━─◈─━─━─━≫\n𝐋𝐚𝐧𝐠 ✨: ${langNames[lang]}\n𝐓𝐞𝐱𝐭 💬 :-\n${rand}\n💥★━━━━━✩━━━━━★🧡`,
      mentions: [{ tag: `@${name}`, id: senderID }]
    };
    return api.sendMessage(formattedMessage, threadID, messageID);
  }
};